from typing import Annotated, TypedDict
import operator

# Without reducer — last write wins
class StateA(TypedDict):
    drafts: list[dict]    # overwritten by last writer

# With reducer — lists are merged
class StateB(TypedDict):
    drafts: Annotated[list[dict], operator.add]  # concatenated

# social_creative returns: {'drafts': ['social1', 'social2']}
# news_creative returns:   {'drafts': ['news1']}
# StateA result: ['news1']                          # lost 2 items!
# StateB result: ['social1', 'social2', 'news1']    # all 3 preserved
